// Build payload without relying on Set node (import/export can wipe Set fields in some n8n Cloud versions).
// Read user selection from Webhook POST: $json.body.pinKey or $json.query.pinKey
const req = $('Publish Demo Pin (POST)').first().json || {};
const body = (req.body && typeof req.body === 'object') ? req.body : {};
const query = (req.query && typeof req.query === 'object') ? req.query : {};
const pinKey = String(body.pinKey || query.pinKey || 'herbs_v1').trim();

// Prefer a board_id returned by Sandbox /v5/boards (production board IDs often fail on api-sandbox with 401).
let sandboxBoardId = '';
try {
  const b = $('List Sandbox Boards').first().json || {};
  if (Array.isArray(b.items) && b.items.length && b.items[0].id) {
    sandboxBoardId = String(b.items[0].id).trim();
  }
} catch (e) {}

// Demo pins catalog (single-user private demo)
const PINS = {
  herbs_v1: {
    BOARD_ID: '1124140825679184034',
    IMAGE_URL: 'https://www.daily-life-hacks.com/images/pins/how-to-store-fresh-herbs-to-last-longer_v1.jpg',
    LINK_URL: 'https://www.daily-life-hacks.com/how-to-store-fresh-herbs-to-last-longer',
    PIN_TITLE: 'How to Store Fresh Herbs So They Last Longer',
    PIN_DESCRIPTION: 'Keep herbs fresh longer with a simple storage method that helps reduce waste and saves money. #KitchenTips #FoodStorage #MealPrep',
    ALT_TEXT: 'Fresh parsley cilantro and dill stored upright in jars with water in a home kitchen'
  },
  oats_v1: {
    BOARD_ID: '1124140825679184034',
    IMAGE_URL: 'https://www.daily-life-hacks.com/images/pins/chia-pudding-variations-for-breakfast_v1.jpg',
    LINK_URL: 'https://www.daily-life-hacks.com/chia-pudding-variations-for-breakfast',
    PIN_TITLE: 'Chia Pudding Variations for Breakfast',
    PIN_DESCRIPTION: 'Simple chia pudding variations you can prep ahead for busy mornings. #HealthyBreakfast #MealPrep #HighFiber',
    ALT_TEXT: 'Three chia pudding jars with berries nuts and cocoa toppings on a kitchen counter'
  }
};

const chosen = PINS[pinKey] || null;
if (!chosen) {
  return [{ json: { ok: false, errors: ['Unknown pinKey'], message: 'Unknown pinKey' } }];
}

const BOARD_ID = String(sandboxBoardId || chosen.BOARD_ID || '').trim();
const IMAGE_URL = String(chosen.IMAGE_URL || '').trim();
const LINK_URL = String(chosen.LINK_URL || '').trim();
const PIN_TITLE = String(chosen.PIN_TITLE || '').trim();
const PIN_DESCRIPTION = String(chosen.PIN_DESCRIPTION || '').trim();
const ALT_TEXT = String(chosen.ALT_TEXT || '').trim();

const errors = [];
if (!BOARD_ID) errors.push('BOARD_ID missing (could not list sandbox boards; check OAuth scopes include boards:read and reconnect)');
if (!IMAGE_URL) errors.push('IMAGE_URL missing');
if (!LINK_URL) errors.push('LINK_URL missing');
if (!PIN_TITLE) errors.push('PIN_TITLE missing');
if (!PIN_DESCRIPTION) errors.push('PIN_DESCRIPTION missing');
if (!ALT_TEXT) errors.push('ALT_TEXT missing');

if (errors.length) {
  return [{ json: { ok: false, errors, message: errors.join('; ') } }];
}

return [{
  json: {
    ok: true,
    pinKey,
    board_id_source: sandboxBoardId ? 'sandbox_boards_list' : 'catalog_fallback',
    pinPayload: {
      title: PIN_TITLE,
      description: PIN_DESCRIPTION,
      link: LINK_URL,
      alt_text: ALT_TEXT,
      board_id: BOARD_ID,
      media_source: { source_type: 'image_url', url: IMAGE_URL }
    }
  }
}];

const api = $input.first().json || {};

if (api && api.id) {
  return [{ json: { status: 'PUBLISHED', pin_id: api.id, pinterest_response: JSON.stringify(api).slice(0, 500) } }];
}

return [{ json: { status: 'ERROR', pin_id: '', pinterest_response: JSON.stringify(api || { message: 'Unknown API error' }).slice(0, 500) } }];

const r = $input.first().json || {};
const ok = String(r.status || '') === 'PUBLISHED';
const pinId = String(r.pin_id || '');
const msg = String(r.pinterest_response || '');

const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));

const title = ok ? 'Published' : 'Error';
const color = ok ? '#166534' : '#7c2d12';
const bg = ok ? '#f0fdf4' : '#fff7ed';

const req = $('Publish Demo Pin (POST)').first().json || {};
const currentUrl = String(req.url || '');
let backUrl = 'oauth-demo';
if (currentUrl) backUrl = currentUrl.replace(/\/dlh\/pinterest\/oauth-demo\/publish\/?$/, '/dlh/pinterest/oauth-demo');

const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>${title}</title>
  <style>
    body{font-family:ui-sans-serif,system-ui,-apple-system,Segoe UI,Roboto,Arial;margin:24px}
    .card{max-width:820px;border:1px solid #ddd;border-radius:12px;padding:18px}
    h1{margin:0 0 10px;font-size:20px}
    .box{background:${bg};border:1px solid #ddd;padding:12px;border-radius:10px;color:${color};line-height:1.5}
    code{background:#f5f5f5;padding:2px 6px;border-radius:6px;word-break:break-all}
    a{color:#F29B30;font-weight:800}
  </style>
</head>
<body>
  <div class="card">
    <h1>${title}</h1>
    <div class="box">
      Status: <code>${esc(r.status || '')}</code>
      ${pinId ? `<br/>Pin ID: <code>${esc(pinId)}</code>` : ''}
    </div>
    ${msg ? `<p style="margin-top:12px;color:#444">${esc(msg).slice(0, 400)}</p>` : ''}
    <p style="margin-top:12px"><a href="${esc(backUrl)}">Back to demo page</a></p>
  </div>
</body>
</html>`;

return [{ json: { html } }];
